import { pathExists } from "./pathExists"

export const cleanGlobalPrefix = async (targetDir: string, prefix: string) => {
  const exists = await pathExists(targetDir)
  if (!exists) {
    return []
  }

  const targetStat = await fs.lstat(targetDir)
  if (targetStat.isSymbolicLink()) {
    try {
      await fs.realpath(targetDir)
    } catch {
      await fs.unlink(targetDir)
      return []
    }
  }

  if (!targetStat.isDirectory()) {
    return []
  }

  let entries
  try {
    entries = await fs.readdir(targetDir)
  } catch (error: unknown) {
    const err = error as { code?: string }

    if (err?.code === "ENOENT" || err?.code === "ENOTDIR") {
      return []
    }
    throw error
  }
  const removed = []

  for (const entry of entries) {
    if (!entry.startsWith(prefix)) {
      continue
    }

    const fullPath = path.join(targetDir, entry)
    const stat = await fs.lstat(fullPath)

    if (stat.isSymbolicLink()) {
      await fs.unlink(fullPath)
    } else if (stat.isDirectory()) {
      await fs.rm(fullPath, { recursive: true, force: true })
    } else {
      await fs.unlink(fullPath)
    }

    removed.push(entry)
  }

  return removed
}

import { IDE_REGISTRY } from "../constants/IDE_REGISTRY"

export const findIde = (id: string) => {

  const ide = IDE_REGISTRY.find((entry: any) => entry.id === id)
  if (!ide) {
    throw new Error(`Unknown IDE: ${id}`)
  }
  return ide
}

import { promises as fs } from "node:fs"
import path from "node:path"
import { cleanGlobalPrefix } from "./cleanGlobalPrefix"
import { ensureParentDirectory } from "./ensureParentDirectory"
import { linkOneWithBackup } from "./linkOneWithBackup"

export const linkRuleTarget = async (ruleTarget: any) => {
  let cleaned: string[] = []

  if (ruleTarget.cleanup) {

    cleaned = await cleanGlobalPrefix(ruleTarget.cleanup.dir, ruleTarget.cleanup.prefix)
  }

  let linked = 0
  let copied = 0

  for (const link of ruleTarget.links) {

    await ensureParentDirectory(link.target)

    if (link.method === "copy") {

      const sourceStat = await fs.lstat(link.source)

      await fs.mkdir(path.dirname(link.target), { recursive: true })

      if (sourceStat.isDirectory()) {

        await fs.rm(link.target, { recursive: true, force: true })

        await fs.cp(link.source, link.target, { recursive: true, dereference: true })
      } else {

        const content = await fs.readFile(link.source, "utf8")

        await fs.writeFile(link.target, content, "utf8")
      }

      copied++
    } else {

      await linkOneWithBackup({ source: link.source, target: link.target })
      linked++
    }
  }

  return { cleaned, linked, copied }
}

/**
 * Detect if umbrella rule should become a workflow or stay as a rule
 * @param {object} parsed - Parsed MDC with frontmatter and content
 * @param {string} _rulePath - Path to the rule file
 * @returns {object} - { isWorkflow: boolean, content: string }
 */

export function detectUmbrellaType(parsed: any, _rulePath: string) {

  const { content } = parsed

  const hasSequentialSteps = /(?:step|first|then|next|finally)/i.test(content)

  const hasNumberedList = /^\d+\./m.test(content)

  const referenceCount = (content.match(/\.cursor\/rules\//g) || []).length
  const isMainlyReferences = referenceCount > 3
  return {
    isWorkflow: hasSequentialSteps && hasNumberedList && !isMainlyReferences,

    content,
  }
}

/**
 * Get Antigravity activation mode from frontmatter
 * @param {object} frontmatter - Parsed MDC frontmatter
 * @returns {string} - Antigravity activation mode
 */

export function getAntigravityActivation(frontmatter: any) {

  const { alwaysApply, globs } = frontmatter
  if (alwaysApply === true) {
    return "Always On"
  }

  if (globs && globs.trim() !== "") {

    return `Glob: ${globs}`
  }

  return "Model Decision"
}

/**
 * Split content if it exceeds Antigravity's 12,000 character limit
 * @param {string} content - Rule content
 * @param {string} ruleName - Rule name for splitting
 * @returns {Array<{name: string, content: string}>} - Split rules or original
 */
export function splitForAntigravity(content: string, ruleName: string) {
  const MAX_LENGTH = 12000
  if (content.length <= MAX_LENGTH) {
    return [{ name: ruleName, content }]
  }

  const sections = content.split(/(?=\n## )/g)
  const parts = []
  let currentPart: string[] = []
  let currentLength = 0
  let partIndex = 1
  for (const section of sections) {
    if (currentLength + section.length > MAX_LENGTH && currentPart.length > 0) {
      // Finalize current part
      parts.push({

        name: `${ruleName}-part${partIndex}`,
        content: currentPart.join(""),
      })
      currentPart = [section]
      currentLength = section.length
      partIndex++
    } else {
      currentPart.push(section)
      currentLength += section.length
    }
  }

  if (currentPart.length > 0) {
    parts.push({

      name: partIndex > 1 ? `${ruleName}-part${partIndex}` : ruleName,
      content: currentPart.join(""),
    })
  }

  return parts
}

import { promises as fs } from "node:fs"
import path from "node:path"
import { parseMdc } from "../../utils/parseMdc"

/**
 * Process a single source file: read, parse, and get relative path
 * @param {string} file - File path
 * @param {string} sourceDir - Source directory
 * @returns {Promise<{content: string, parsed: object, relativePath: string}>}
 */
export async function processSourceFile(file: string, sourceDir: string) {
  const content = await fs.readFile(file, "utf8")
  const parsed = parseMdc(content)
  const relativePath = path.relative(sourceDir, file)

  const parsedWithContent = { ...parsed, content: parsed.body ?? "" }
  return { content, parsed: parsedWithContent, relativePath }
}

import path from "node:path"
import { compareRuleFile } from "../helpers/utils/compareRuleFile"
import { processSourceFile } from "../helpers/utils/processSourceFile"
import { toAntigravityRule } from "./toAntigravityRule"

/**
 * Check if Antigravity rules are in sync
 * @param {string[]} sourceFiles - Array of source .mdc files
 * @param {string} sourceDir - Source directory path
 * @param {string} targetDir - Target .agent/rules directory
 * @returns {Promise<string[]>} - Array of error messages
 */
export async function checkAntigravityRules(
  sourceFiles: string[],
  sourceDir: string,
  targetDir: string,
) {
  const errors = []
  const workflowsDir = path.join(path.dirname(targetDir), "workflows")
  for (const file of sourceFiles) {
    const { parsed, relativePath } = await processSourceFile(file, sourceDir)
    const converted = toAntigravityRule(parsed, relativePath)

    for (const part of converted) {

      const targetPath = part.isWorkflow
        ? // eslint-disable-next-line @typescript-eslint/restrict-template-expressions, @typescript-eslint/no-unsafe-member-access
          path.join(workflowsDir, `${part.name}.md`)
        : // eslint-disable-next-line @typescript-eslint/restrict-template-expressions, @typescript-eslint/no-unsafe-member-access
          path.join(targetDir, `${part.name}.md`)

      const { missing, outdated } = await compareRuleFile(targetPath, part.content)
      if (missing) errors.push(`Missing Antigravity rule: ${targetPath}`)
      else if (outdated) errors.push(`Outdated Antigravity rule: ${targetPath}`)
    }
  }

  return errors
}

import { promises as fs } from "node:fs"
import path from "node:path"
import { listFilesRecursive } from "../../fs/utils/listFilesRecursive"
import { sha256 } from "../../hash/utils/sha256"
import { normalizeRel } from "./normalizeRel"
import { toClaudeRule } from "./toClaudeRule"

export const checkClaudeRules = async (
  sourceFiles: string[],
  sourceDir: string,
  claudeRulesDir: string,
) => {
  const expectedMap = new Map()
  const mdcFiles = sourceFiles
    .filter((sourcePath: string) => sourcePath.endsWith(".mdc"))

    .sort((a: string, b: string) => a.localeCompare(b))

  for (const sourcePath of mdcFiles) {
    const rel = normalizeRel(path.relative(sourceDir, sourcePath)).replace(/\.mdc$/, ".md")
    const sourceContent = await fs.readFile(sourcePath, "utf8")

    expectedMap.set(rel, sha256(`${toClaudeRule(sourceContent)}\n`))
  }

  let actualFiles
  try {
    actualFiles = await listFilesRecursive(claudeRulesDir)
  } catch {
    return ["Missing generated directory: .claude/rules"]
  }

  const actualMap = new Map()
  for (const actualPath of actualFiles) {
    const rel = normalizeRel(path.relative(claudeRulesDir, actualPath))

    const content = await fs.readFile(actualPath, "utf-8")
    actualMap.set(rel, sha256(content))
  }

  const errors = []

  for (const [filePath, hash] of expectedMap.entries()) {
    if (!actualMap.has(filePath)) {

      errors.push(`Missing generated file: .claude/rules/${filePath}`)
      continue
    }

    if (actualMap.get(filePath) !== hash) {

      errors.push(`Outdated generated file: .claude/rules/${filePath}`)
    }
  }

  for (const filePath of actualMap.keys()) {
    if (!expectedMap.has(filePath)) {

      errors.push(`Unexpected generated file: .claude/rules/${filePath}`)
    }
  }

  return errors
}

import { promises as fs } from "node:fs"
import path from "node:path"
import { listFilesRecursive } from "../../fs/utils/listFilesRecursive"
import { sha256 } from "../../hash/utils/sha256"
import { normalizeRel } from "./normalizeRel"

export const checkCursorRules = async (
  sourceFiles: string[],
  sourceDir: string,
  cursorDir: string,
) => {
  const sourceMap = new Map()

  for (const sourcePath of sourceFiles) {
    const rel = normalizeRel(path.relative(sourceDir, sourcePath))
    const content = await fs.readFile(sourcePath, "utf-8")
    sourceMap.set(rel, sha256(content))
  }

  let cursorFiles
  try {
    cursorFiles = await listFilesRecursive(cursorDir)
  } catch {
    return ["Missing .cursor/rules directory"]
  }

  const cursorMap = new Map()
  for (const cursorPath of cursorFiles) {
    const rel = normalizeRel(path.relative(cursorDir, cursorPath))

    const content = await fs.readFile(cursorPath, "utf-8")
    cursorMap.set(rel, sha256(content))
  }

  const errors = []

  for (const [filePath, hash] of sourceMap.entries()) {
    if (!cursorMap.has(filePath)) {

      errors.push(`Missing generated file: .cursor/rules/${filePath}`)
      continue
    }

    if (cursorMap.get(filePath) !== hash) {

      errors.push(`Outdated generated file: .cursor/rules/${filePath}`)
    }
  }

  for (const filePath of cursorMap.keys()) {
    if (!sourceMap.has(filePath)) {

      errors.push(`Unexpected generated file: .cursor/rules/${filePath}`)
    }
  }

  return errors
}

