/**
 * Sync rules to Antigravity format (.agent/rules/)
 * @param {string[]} sourceFiles - Array of source .mdc files
 * @param {string} sourceDir - Source directory path
 * @param {string} targetDir - Target .agent/rules directory
 */
export async function syncAntigravityRules(
  sourceFiles: string[],
  sourceDir: string,
  targetDir: string,
) {
  await ensureDir(targetDir)
  const workflowsDir = path.join(path.dirname(targetDir), "workflows")
  await ensureDir(workflowsDir)
  for (const file of sourceFiles) {
    const { parsed, relativePath } = await processSourceFile(file, sourceDir)
    const converted = toAntigravityRule(parsed, relativePath)

    for (const part of converted) {

      const targetPath = part.isWorkflow
        ? // eslint-disable-next-line @typescript-eslint/restrict-template-expressions, @typescript-eslint/no-unsafe-member-access
          path.join(workflowsDir, `${part.name}.md`)
        : // eslint-disable-next-line @typescript-eslint/restrict-template-expressions, @typescript-eslint/no-unsafe-member-access
          path.join(targetDir, `${part.name}.md`)

      await writeRuleFile(targetPath, part.content)
    }
  }
}

import { convertToAntigravityMentions } from "../antigravity/utils/convertToAntigravityMentions"
import { detectUmbrellaType } from "../antigravity/utils/detectUmbrellaType"
import { generateAntigravityHeader } from "../antigravity/utils/generateAntigravityHeader"
import { getAntigravityActivation } from "../antigravity/utils/getAntigravityActivation"
import { splitForAntigravity } from "../antigravity/utils/splitForAntigravity"

/**
 * Main conversion function
 * @param {object} parsed - Parsed MDC with frontmatter and content
 * @param {string} rulePath - Original rule path
 * @returns {Array<{name: string, content: string, isWorkflow: boolean}>}
 */

export function toAntigravityRule(parsed: any, rulePath: string) {

  const activation = getAntigravityActivation(parsed.frontmatter)

  const header = generateAntigravityHeader(parsed.frontmatter, activation)

  const content = convertToAntigravityMentions(parsed.content, rulePath)
  const umbrellaInfo = detectUmbrellaType(parsed, rulePath)
  const fullContent = header + content
  const ruleName = rulePath.replace(/\.mdc$/, "").replace(/\//g, "-")
  const parts = splitForAntigravity(fullContent, ruleName)

  return parts.map((part: any) => ({
    ...part,
    isWorkflow: umbrellaInfo.isWorkflow,
  }))
}

import { addWindsurfAnnotations } from "../windsurf/utils/addWindsurfAnnotations"
import { convertToWindsurfReferences } from "../windsurf/utils/convertToWindsurfReferences"
import { formatWindsurfFrontmatter } from "../windsurf/utils/formatWindsurfFrontmatter"

/**
 * Main conversion function
 * @param {object} parsed - Parsed MDC with frontmatter and content
 * @param {string} _rulePath - Original rule path
 * @returns {string} - Windsurf-formatted rule
 */

export function toWindsurfRule(parsed: any, _rulePath: string) {

  const frontmatter = formatWindsurfFrontmatter(parsed.frontmatter)

  let content = convertToWindsurfReferences(parsed.content)

  content = addWindsurfAnnotations(content, parsed.frontmatter)
  return `${frontmatter}\n\n${content}`
}

/**
 * Add Windsurf-specific annotations
 * @param {string} content - Rule content
 * @param {object} frontmatter - Parsed frontmatter
 * @returns {string} - Content with Windsurf annotations
 */

export function addWindsurfAnnotations(content: string, frontmatter: any) {
  let annotated = content

  if (frontmatter.globs) {

    const fileTypes = frontmatter.globs.split(",").map((g: string) => g.trim())

    annotated = `<!-- Windsurf Context: ${fileTypes.join(", ")} -->\n\n${annotated}`
  }

  return annotated
}

/**
 * Convert to Windsurf rule frontmatter format
 * @param {object} frontmatter - Parsed MDC frontmatter
 * @returns {string} - Formatted frontmatter for Windsurf
 */
export function formatWindsurfFrontmatter(frontmatter: Record<string, unknown>) {
  const lines = ["---"]
  if (frontmatter.description) {

    lines.push(`description: "${frontmatter.description}"`)
  }

  if (frontmatter.globs) {

    lines.push(`globs: "${frontmatter.globs}"`)
  }

  if (frontmatter.alwaysApply !== undefined) {

    lines.push(`alwaysApply: ${frontmatter.alwaysApply}`)
  }

  if (frontmatter.priority) {

    lines.push(`priority: ${frontmatter.priority}`)
  } else {
    // Default priority based on alwaysApply
    lines.push(`priority: ${frontmatter.alwaysApply ? "high" : "medium"}`)
  }

  lines.push("---")
  return lines.join("\n")
}

